import { useParams } from "react-router-dom";
import { useState, useEffect } from "react";
import products from "../data/ProductData"; // dummy products
import "../index.css";

function ProductDetails() {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [mainImage, setMainImage] = useState("");

  useEffect(() => {
    // 1️⃣ Try to find in dummy products
    const dummyProduct = products.find((p) => String(p.id) === id);
    if (dummyProduct) {
      setProduct(dummyProduct);
      setMainImage(dummyProduct.image);
      return;
    }

    // 2️⃣ If not found, fetch from DB
    fetch('http://localhost:5000/api/products/${id}') // update with your API URL
      .then((res) => res.json())
      .then((data) => {
        setProduct(data);
        setMainImage(data.image);
      })
      .catch((err) => console.error(err));
  }, [id]);

  if (!product) {
    return <h2 className="not-found">Product Not Found</h2>;
  }

  const images = [product.image, ...(product.images || [])];

  return (
    <div className="product-details">
      {/* Left: Product Images */}
      <div className="image-section">
        <div className="main-image">
          <img src={mainImage} alt={product.name} />
        </div>

        <div className="thumbnails">
          {images.map((img, idx) => (
            <div
              key={idx}
              className={'thumb ${mainImage === img ? "active" : ""}'}
              onClick={() => setMainImage(img)}
            >
              <img src={img} alt={'${product.name}-${idx}'} />
            </div>
          ))}
        </div>
      </div>

      {/* Right: Details */}
      <div className="details-section">
        <h1>{product.name}</h1>
        <p>{product.description}</p>
        <div className="price">
          <span className="offer">₹{product.oPrice || product.price}</span>
          {product.offerPrice && (
            <span className="old">₹{product.price}</span>
          )}
        </div>
        <button className="btn">Add to Cart</button>
        <button className="btn buy">Buy Now</button>
      </div>
    </div>
  );
}

export default ProductDetails;
